import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { PieChart } from '@mui/x-charts';
import response from './response.json';

interface InvoiceSummary {
  pending: {
    count: number;
    totalAmount: number;
  };
  paid: {
    count: number;
    totalAmount: number;
  };
  overdue: {
    count: number;
    totalAmount: number;
  };
}

interface MetaData {
  theme: string;
  dataMode: string;
  layout: string;
  primaryColor: string;
  accentColor: string;
  chartTypes: string[];
}

export default function Widget() {
  const summary = response.data.summary as InvoiceSummary;
  const meta = response.meta as MetaData;

  const chartData = [
    { label: 'Paid', value: summary.paid.totalAmount, color: meta.primaryColor },
    { label: 'Pending', value: summary.pending.totalAmount, color: meta.accentColor },
    { label: 'Overdue', value: summary.overdue.totalAmount, color: '#F44336' },
  ];

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={700} sx={{ color: meta.primaryColor }}>
              Invoice Summary
            </Typography>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <PieChart
              height={200}
              series={[
                {
                  data: chartData.map((item) => item.value),
                  color: chartData.map((item) => item.color),
                  innerRadius: 0.6,
                  outerRadius: 0.9,
                  cornerRadius: 5,
                },
              ]}
              xAxis={[{ data: chartData.map((item) => item.label), hide: true }]}
              margin={{ top: 10, bottom: 10, left: 10, right: 10 }}
            />
          </Box>

          <Stack direction="row" spacing={1}>
            {chartData.map((item) => (
              <Chip
                key={item.label}
                label={`${item.label}: $${item.value.toLocaleString()}`}
                sx={{ fontSize: '11px', bgcolor: item.color, color: '#FFFFFF' }}
              />
            ))}
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
